// ============================================================
// BriefFeed 配置中心 — 修改此节点来调整所有抓取与评分参数
// rss_sources 对应 config/rss_sources.json（不含 template）
// 其余设置对应 config/settings.json（不含 template）
// ============================================================
const CONFIG = {

  // ---------- arXiv ----------
  arxiv_rss_categories: ['cs.AI', 'cs.HC', 'cs.LG', 'cs.RO'],
  paper_keywords: [
    '("human computer interaction" OR HCI) AND ("large language model" OR LLM OR agent)',
    '("computer aided design" OR CAD) AND ("artificial intelligence" OR "machine learning")',
    '("multimodal" OR "multi-modal") AND ("3D" OR "design" OR "engineering")',
    '"design automation" AND ("AI" OR "agent" OR "intelligent")',
    '"engineering assistant" OR "CAD copilot" OR "design intelligence"',
  ],

  // ---------- GitHub ----------
  github_keywords: [
    'CAD AI assistant',
    'engineering design agent LLM',
    'CAD copilot',
    'HCI design tool AI',
    'design automation agent',
  ],
  github_quality: {
    stars_min:          10,   // star 数最低门槛（降低以避免漏掉新兴项目）
    pushed_within_days: 365,  // 最近活跃天数（0 = 不过滤）
    keep_top:           8,    // 每个关键词最多保留几个（按 star 降序）
  },

  // ---------- RSS 源（来自 config/rss_sources.json）----------
  rss_sources: [
    { name: 'OpenAI Blog',              url: 'https://openai.com/news/rss.xml',                                                                                    category: 'AI公司博客',           enabled: true  },
    { name: 'Anthropic News',           url: 'https://www.anthropic.com/news/rss.xml',                                                                             category: 'AI公司博客',           enabled: true  },
    { name: 'Google DeepMind Blog',     url: 'https://deepmind.com/blog/feed/basic/',                                                                              category: 'AI公司博客',           enabled: true  },
    { name: 'Hugging Face Blog',        url: 'https://huggingface.co/blog/feed.xml',                                                                               category: 'AI工具',               enabled: true  },
    { name: 'LangChain Blog',           url: 'https://blog.langchain.dev/rss/',                                                                                    category: 'AI工具',               enabled: true  },
    { name: 'LlamaIndex Blog',          url: 'https://www.llamaindex.ai/blog/rss.xml',                                                                             category: 'AI工具',               enabled: true  },
    { name: 'Jina AI',                  url: 'https://jina.ai/news/rss.xml',                                                                                       category: 'AI工具',               enabled: true  },
    { name: 'Microsoft Research Blog',  url: 'https://www.microsoft.com/en-us/research/feed/',                                                                     category: '研究机构',             enabled: true  },
    { name: 'deeplearning.ai',          url: 'https://rsshub.bestblogs.dev/deeplearning/the-batch',                                                                category: '研究机构',             enabled: true  },
    { name: 'The GitHub Blog',          url: 'https://github.blog/feed/',                                                                                          category: '开源社区',             enabled: true  },
    { name: 'Vercel News',              url: 'https://vercel.com/atom',                                                                                            category: '工程/AI产品',          enabled: true  },
    { name: "Simon Willison's Weblog",  url: 'https://simonwillison.net/atom/everything/',                                                                         category: 'AI工程/独立技术博客',  enabled: true  },
    { name: 'Latent Space',             url: 'https://www.latent.space/feed',                                                                                      category: 'AI工程/Agent',         enabled: true  },
    { name: 'UX Magazine',              url: 'https://uxmag.com/feed/',                                                                                            category: 'HCI/UX',               enabled: true  },
    { name: 'Last Week in AI',          url: 'https://lastweekin.ai/feed/',                                                                                        category: 'AI媒体',               enabled: false },
  ],

  // ---------- 评分 & 筛选（来自 config/settings.json）----------
  scoring_weights:       { relevance: 0.5, novelty: 0.3, transferability: 0.2 },
  max_items_per_section: 10,
  min_score_threshold:   4,    // 三维整数分之和阈值（满分 15，建议 4~6）

  // ---------- LLM ----------
  llm_model:             'deepseek-ai/DeepSeek-V3',
  llm_batch_size:        20,
  llm_max_concurrency:   3,    // 建议 2~5，视 API 限流而定

  // ---------- 抓取量 ----------
  fresh_days:            7,    // 只保留最近 N 天内容（0 = 不过滤）
  rss_items_per_source:  10,
  arxiv_results_per_kw:  8,
  github_results_per_kw: 20,   // 抓取候选数（过滤前），应大于 keep_top

  // ---------- 输出 ----------
  output_dir: '/briefeed-output',

  // ---------- LLM 系统提示词（来自 config/researcher_profile.md）----------
  system_prompt: 'You are filtering daily professional updates for a researcher. All your output must be in Chinese.\n\nThe researcher is mainly interested in:\n1. AI for CAD and engineering design\n2. Human-AI interaction, especially CHI/UIST-style research\n3. Intelligent engineering assistants, CAD copilots, and design automation systems\n4. Agentic or multi-agent workflows when they are relevant to engineering tasks\n5. Methods, frameworks, open-source tools, and product ideas that can be transferred into real systems\n\nThe researcher especially values:\n- Content that is directly useful for research or project development\n- Methodological novelty, system design insight, and engineering applicability\n- Work related to interactive design tools, engineering intelligence, and AI-assisted workflows\n- Ideas that can inform the development of CAD copilot / engineering assistant / design intelligence systems\n\nThe researcher is less interested in:\n- Generic AI news or hype without technical substance\n- Marketing-heavy announcements\n- Product updates without technical depth\n- Content with weak relevance to design, engineering, HCI, or agent systems\n\nReturn ONLY a valid JSON array. For each item provide these fields:\n- id: original index (integer)\n- relevance: integer 0-5. How closely the topic matches the researcher interests above.\n  0=unrelated, 1=tangential, 2=somewhat relevant, 3=relevant, 4=highly relevant, 5=core topic\n- novelty: integer 0-5. How new, surprising, or non-obvious the contribution is.\n  0=rehash, 1=incremental, 2=slight advance, 3=notable, 4=significant, 5=breakthrough\n- transferability: integer 0-5. How directly the ideas/code/methods can be applied to the researcher\'s own work.\n  0=not applicable, 1=inspirational only, 2=partial idea, 3=useful method, 4=directly adoptable, 5=ready to use\n- category: "论文" | "博客" | "GitHub"\n- direction: "AI+CAD" | "HCI" | "设计工具" | "多模态" | "Agent系统" | "其他"\n- summary_zh: 2-3 sentence Chinese summary of what this item is\n- value_zh: 1-2 sentence Chinese explanation of why it matters to this researcher\n- skip: true ONLY if relevance <= 1 (clearly off-topic), otherwise false\n\nCRITICAL:\n1. Output ONLY a valid JSON array. No markdown. No extra text.\n2. ALL scores must be integers 0-5. Never use decimals.\n3. Do NOT modify any URLs. Use URLs exactly as provided.',
};

console.log('配置加载完成：RSS源 ' + CONFIG.rss_sources.filter(function(s){return s.enabled;}).length + ' 个已启用，arxiv分类 ' + CONFIG.arxiv_rss_categories.length + ' 个，github关键词 ' + CONFIG.github_keywords.length + ' 个');
return [{ json: { config: CONFIG } }];

// 从上游节点接收配置
const CONFIG = $input.first().json.config;

// ============================================================
// 工具函数
// ============================================================
function extractTag(xml, tag) {
  const m = xml.match(new RegExp('<' + tag + '[^>]*>([^]*?)<[/]' + tag + '>', 'i'));
  return m ? m[1].trim() : '';
}
function extractAttrHref(xml) {
  const m = xml.match(/<link[^>]+href=['"]([^'"]+)['"]/i);
  return m ? m[1] : '';
}
function stripHtml(s) {
  return s
    .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/gi, '$1')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#\d+;/g, '')
    .trim();
}
function parseRSS(xml, sourceName, category, maxItems) {
  const items = [];
  const rx = /<(?:item|entry)[^]*?<[/](?:item|entry)>/gi;
  for (const chunk of (xml.match(rx) || []).slice(0, maxItems || 10)) {
    const title = stripHtml(extractTag(chunk, 'title'));
    const link  = (extractTag(chunk, 'link') || extractAttrHref(chunk)).trim();
    const desc  = stripHtml(extractTag(chunk, 'summary') || extractTag(chunk, 'description') || extractTag(chunk, 'content') || '');
    const pub   = extractTag(chunk, 'pubDate') || extractTag(chunk, 'published') || extractTag(chunk, 'updated') || '';
    if (!title || !link || !link.startsWith('http')) continue;
    items.push({ title, url: link, abstract: desc.slice(0, 400), date: pub ? new Date(pub).toISOString().split('T')[0] : new Date().toISOString().split('T')[0], source: sourceName, source_type: 'blog', category });
  }
  return items;
}
function parseArxiv(xml, label) {
  const items = [];
  for (const chunk of (xml.match(/<entry[^]*?<[/]entry>/gi) || [])) {
    const title   = stripHtml(extractTag(chunk, 'title')).replace(/\s+/g, ' ').trim();
    const id      = extractTag(chunk, 'id').trim();
    const summary = stripHtml(extractTag(chunk, 'summary'));
    const pub     = extractTag(chunk, 'published') || '';
    if (!title || !id) continue;
    items.push({ title, url: id.replace('http://arxiv.org/abs/', 'https://arxiv.org/abs/'), abstract: summary.slice(0, 500), date: pub ? pub.split('T')[0] : new Date().toISOString().split('T')[0], source: 'arXiv (' + label + ')', source_type: 'paper', category: label });
  }
  return items;
}
function isFresh(item, cutoff) {
  if (!cutoff || !item.date) return true;
  try { return new Date(item.date).getTime() >= cutoff; } catch(e) { return true; }
}

// ============================================================
// HTTP 工具函数
// ============================================================
const https = require('https');
const http = require('http');
const nodeUrl = require('url');
function httpGet(urlStr, headers, timeoutMs) {
  return new Promise(function(resolve, reject) {
    const u = nodeUrl.parse(urlStr);
    const isHttps = u.protocol === 'https:';
    const lib = isHttps ? https : http;
    const opts = { hostname: u.hostname, port: u.port ? parseInt(u.port) : (isHttps ? 443 : 80), path: (u.pathname || '/') + (u.search || ''), method: 'GET', headers: Object.assign({ 'User-Agent': 'BriefFeed/1.0' }, headers || {}), timeout: timeoutMs || 18000 };
    const req = lib.request(opts, function(res) {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        return resolve(httpGet(res.headers.location, headers, timeoutMs));
      }
      const chunks = [];
      res.on('data', function(c) { chunks.push(c); });
      res.on('end', function() { resolve(Buffer.concat(chunks).toString('utf-8')); });
    });
    req.on('timeout', function() { req.destroy(); reject(new Error('Request timed out')); });
    req.on('error', reject);
    req.end();
  });
}
function httpGetJson(urlStr, headers, timeoutMs) {
  return httpGet(urlStr, headers, timeoutMs).then(function(text) { return JSON.parse(text); });
}

// ============================================================
// 并发抓取
// ============================================================
const errors = [];
const T = 18000;
const cutoff = CONFIG.fresh_days > 0 ? Date.now() - CONFIG.fresh_days * 86400000 : 0;
const maxRSS = CONFIG.rss_items_per_source || 10;
const maxArxiv = CONFIG.arxiv_results_per_kw || 8;
const maxGH = CONFIG.github_results_per_kw || 20;

// --- 1. arXiv RSS ---
const arxivRssResults = await Promise.allSettled(
  CONFIG.arxiv_rss_categories.map(function(cat) {
    return httpGet('https://rss.arxiv.org/rss/' + cat, {}, T)
      .then(function(xml) {
        return parseRSS(xml, 'arXiv ' + cat, cat, maxRSS).map(function(i) { return Object.assign({}, i, { source_type: 'paper' }); });
      });
  })
);
const arxivRssItems = [];
arxivRssResults.forEach(function(r, i) {
  if (r.status === 'fulfilled') { arxivRssItems.push(...r.value); }
  else { errors.push('arXiv RSS ' + CONFIG.arxiv_rss_categories[i] + ': ' + r.reason.message); }
});

// --- 2. arXiv API 关键词搜索 ---
const arxivApiResults = await Promise.allSettled(
  CONFIG.paper_keywords.map(function(kw) {
    const url = 'https://export.arxiv.org/api/query?search_query=' + encodeURIComponent(kw) + '&start=0&max_results=' + maxArxiv + '&sortBy=submittedDate&sortOrder=descending';
    return httpGet(url, {}, T).then(function(xml) { return parseArxiv(xml, kw.slice(0, 40)); });
  })
);
const arxivApiItems = [];
arxivApiResults.forEach(function(r, i) {
  if (r.status === 'fulfilled') { arxivApiItems.push(...r.value); }
  else { errors.push('arXiv API "' + CONFIG.paper_keywords[i].slice(0, 30) + '": ' + r.reason.message); }
});

// --- 3. RSS 源 ---
const enabledSources = CONFIG.rss_sources.filter(function(s) { return s.enabled; });
const rssResults = await Promise.allSettled(
  enabledSources.map(function(src) {
    return httpGet(src.url, { 'User-Agent': 'BriefFeed/1.0' }, T)
      .then(function(xml) { return parseRSS(xml, src.name, src.category, maxRSS); });
  })
);
const rssItems = [];
rssResults.forEach(function(r, i) {
  if (r.status === 'fulfilled') { rssItems.push(...r.value); }
  else { errors.push('RSS ' + enabledSources[i].name + ': ' + r.reason.message); }
});

// --- 4. GitHub ---
const ghHeaders = { 'Accept': 'application/vnd.github+json', 'User-Agent': 'BriefFeed/1.0' };
const ghToken = $env.GITHUB_TOKEN || '';
if (ghToken) { ghHeaders['Authorization'] = 'token ' + ghToken; }
const ghQuality = CONFIG.github_quality || {};
const ghStarsMin = ghQuality.stars_min != null ? ghQuality.stars_min : 10;
const ghPushedDays = ghQuality.pushed_within_days != null ? ghQuality.pushed_within_days : 365;
const ghKeepTop = ghQuality.keep_top || 8;
const ghPushedCutoff = ghPushedDays > 0 ? Date.now() - ghPushedDays * 86400000 : 0;
const githubResults = await Promise.allSettled(
  CONFIG.github_keywords.map(function(kw) {
    const url = 'https://api.github.com/search/repositories?q=' + encodeURIComponent(kw) + '&sort=stars&order=desc&per_page=' + maxGH;
    return httpGetJson(url, ghHeaders, T).then(function(d) {
      if (!d || !d.items) return [];
      return d.items
        .filter(function(repo) {
          if (repo.stargazers_count < ghStarsMin) return false;
          if (ghPushedCutoff && repo.pushed_at) {
            if (new Date(repo.pushed_at).getTime() < ghPushedCutoff) return false;
          }
          return true;
        })
        .slice(0, ghKeepTop)
        .map(function(repo) {
          const pushedDate = (repo.pushed_at || '').split('T')[0];
          const createdDate = (repo.created_at || '').split('T')[0];
          return {
            title: repo.full_name,
            url: repo.html_url,
            abstract: (repo.description || '无描述').slice(0, 300),
            date: pushedDate || new Date().toISOString().split('T')[0],
            source: 'GitHub (' + kw + ')',
            source_type: 'github',
            category: 'GitHub',
            stars: repo.stargazers_count,
            extra: '⭐ ' + repo.stargazers_count + ' | 🍴 ' + repo.forks_count + ' | ' + (repo.language || '?') + ' | 最近推送 ' + pushedDate + ' | 创建 ' + createdDate,
          };
        });
    });
  })
);
const githubItems = [];
githubResults.forEach(function(r, i) {
  if (r.status === 'fulfilled') { githubItems.push(...r.value); }
  else { errors.push('GitHub "' + CONFIG.github_keywords[i] + '": ' + r.reason.message); }
});

// --- 合并 & 新鲜度过滤 ---
const allItems = [...arxivRssItems, ...arxivApiItems, ...rssItems, ...githubItems]
  .filter(function(item) { return isFresh(item, cutoff); });

console.log('并发抓取完成：论文RSS ' + arxivRssItems.length + ' | 论文API ' + arxivApiItems.length + ' | RSS ' + rssItems.length + ' | GitHub ' + githubItems.length + ' | 新鲜过滤后 ' + allItems.length + ' 条（' + CONFIG.fresh_days + ' 天内）');

return [{ json: { items: allItems, config: CONFIG, errors: errors, fetchedAt: new Date().toISOString() } }];

const data = $input.first().json;
const items = data.items;
const seen = new Set();
const deduped = items.filter(function(item) {
  if (!item.title || !item.url || !item.url.startsWith('http')) return false;
  const key = item.url.replace(/v\d+$/, '').toLowerCase().replace(/\/$/, '');
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});
console.log('抓取完成：原始 ' + items.length + ' 条 → 去重后 ' + deduped.length + ' 条');
if (data.errors && data.errors.length) console.log('警告：' + data.errors.join(' | '));
return [{ json: { items: deduped, config: data.config, errors: data.errors, fetchedAt: data.fetchedAt } }];

const data = $input.first().json;
const items = data.items;
const config = data.config;

const API_KEY = $env.SILICONFLOW_API_KEY;
if (!API_KEY) throw new Error('请配置环境变量 SILICONFLOW_API_KEY');

const SYSTEM_PROMPT = config.system_prompt;
if (!SYSTEM_PROMPT) throw new Error('配置中缺少 system_prompt，请检查读取配置节点');

const batchSize   = config.llm_batch_size      || 20;
const maxConc     = config.llm_max_concurrency  || 3;
// weights 用于将三维整数分（0-5）聚合为单一排序分（0-15），不再用 0-1 小数
const weights     = config.scoring_weights      || { relevance: 0.5, novelty: 0.3, transferability: 0.2 };
const minTotal    = config.min_score_threshold  || 4;   // 三维之和 >= 4 才保留（15 分制）
const model       = config.llm_model            || 'deepseek-ai/DeepSeek-V3';
const https_llm   = require('https');

function callLLM(batch, batchOffset) {
  const payload = batch.map(function(item, idx) {
    return { id: batchOffset + idx, title: item.title, url: item.url, source: item.source, type: item.source_type, date: item.date, abstract: (item.abstract || '').slice(0, 400) };
  });
  const userMsg = 'Analyze the following ' + batch.length + ' items and return a JSON array:\n\n' + JSON.stringify(payload, null, 2) + '\n\nReturn ONLY the JSON array, no markdown.';
  const bodyStr = JSON.stringify({ model: model, messages: [{ role: 'system', content: SYSTEM_PROMPT }, { role: 'user', content: userMsg }], max_tokens: 4096, temperature: 0.1, stream: false });
  return new Promise(function(resolve, reject) {
    const opts = { hostname: 'api.siliconflow.cn', port: 443, path: '/v1/chat/completions', method: 'POST', headers: { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(bodyStr) }, timeout: 180000 };
    const req = https_llm.request(opts, function(res) {
      const chunks = [];
      res.on('data', function(c) { chunks.push(c); });
      res.on('end', function() {
        try {
          const result = JSON.parse(Buffer.concat(chunks).toString('utf-8'));
          const content = (result.choices && result.choices[0] && result.choices[0].message) ? result.choices[0].message.content : '';
          let jsonStr = content;
          const mdMatch = content.match(/```(?:json)?\n?([^]*?)\n?```/);
          if (mdMatch) jsonStr = mdMatch[1];
          let evals = [];
          try { evals = JSON.parse(jsonStr.trim()); } catch(e2) {
            const arrMatch = jsonStr.match(/\[[^]*\]/);
            if (arrMatch) evals = JSON.parse(arrMatch[0]);
          }
          resolve(evals);
        } catch(e) { reject(e); }
      });
    });
    req.on('timeout', function() { req.destroy(); reject(new Error('LLM request timed out')); });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

const batches = [];
for (let i = 0; i < items.length; i += batchSize) {
  batches.push({ batch: items.slice(i, i + batchSize), offset: i });
}

const scored = [];
for (let gi = 0; gi < batches.length; gi += maxConc) {
  const group = batches.slice(gi, gi + maxConc);
  console.log('并发提交批次 ' + (gi+1) + '~' + Math.min(gi+maxConc, batches.length) + '/' + batches.length);
  const results = await Promise.allSettled(
    group.map(function(b) { return callLLM(b.batch, b.offset); })
  );
  results.forEach(function(r, ri) {
    const b = group[ri];
    let evals = [];
    if (r.status === 'fulfilled') {
      evals = r.value;
    } else {
      console.log('批次 ' + (gi+ri+1) + ' LLM 失败: ' + r.reason.message);
      evals = b.batch.map(function(_, idx) { return { id: b.offset+idx, relevance: 2, novelty: 2, transferability: 2, category: '博客', direction: '未分类', summary_zh: '', value_zh: '（LLM失败）', skip: false }; });
    }
    for (let ei = 0; ei < evals.length; ei++) {
      const ev = evals[ei];
      if (ev.skip) continue;
      const localIdx = ev.id - b.offset;
      if (localIdx < 0 || localIdx >= b.batch.length) continue;
      const orig = b.batch[localIdx];
      // 整数化（防止 LLM 返回小数）
      const rel  = Math.round(Math.min(5, Math.max(0, ev.relevance      || 0)));
      const nov  = Math.round(Math.min(5, Math.max(0, ev.novelty        || 0)));
      const tra  = Math.round(Math.min(5, Math.max(0, ev.transferability || ev.actionability || 0)));
      const total = rel + nov + tra;  // 0~15
      if (total < minTotal) continue;
      // 加权分（用于排序，保持向后兼容 score 字段）
      const wScore = rel * (weights.relevance || 0.5) + nov * (weights.novelty || 0.3) + tra * (weights.transferability || weights.actionability || 0.2);
      const merged = {};
      for (const k in orig) merged[k] = orig[k];
      merged.score            = Math.round(wScore * 100) / 100;  // 加权分，用于排序
      merged.total_score      = total;                            // 三维总分 /15
      merged.relevance        = rel;
      merged.novelty          = nov;
      merged.transferability  = tra;
      merged.category_zh      = ev.category || (orig.source_type === 'paper' ? '论文' : orig.source_type === 'github' ? 'GitHub' : '博客');
      merged.direction        = ev.direction || '其他';
      merged.summary_zh       = ev.summary_zh || orig.abstract || '';
      merged.value_zh         = ev.value_zh || '';
      scored.push(merged);
    }
  });
}

console.log('LLM完成：' + scored.length + ' 条通过阈值，共 ' + batches.length + ' 批次（最大并发 ' + maxConc + '）');
return [{ json: { items: scored, config: config, errors: data.errors, fetchedAt: data.fetchedAt } }];

const data = $input.first().json;
const items = data.items;
const config = data.config;
const maxN = config.max_items_per_section || 10;

const papers  = items.filter(function(i){ return i.source_type === 'paper';  }).sort(function(a,b){ return b.score-a.score; }).slice(0, maxN);
const blogs   = items.filter(function(i){ return i.source_type === 'blog';   }).sort(function(a,b){ return b.score-a.score; }).slice(0, maxN);
const githubs = items.filter(function(i){ return i.source_type === 'github'; }).sort(function(a,b){ return b.score-a.score; }).slice(0, maxN);

const now = new Date();
const pad = function(n){ return String(n).padStart(2,'0'); };
const dateStr = now.getFullYear() + '-' + pad(now.getMonth()+1) + '-' + pad(now.getDate());
const timeStr = pad(now.getHours()) + ':' + pad(now.getMinutes());
const filename = 'briefeed_' + dateStr.replace(/-/g,'') + '_' + pad(now.getHours()) + pad(now.getMinutes()) + '.md';

function fmt(item) {
  const scoreStr = item.total_score != null ? ' | 评分 ' + item.total_score + '/15（相关' + (item.relevance||0) + ' 新颖' + (item.novelty||0) + ' 迁移' + (item.transferability||0) + '）' : '';
  const extra = item.extra ? '
- **附加信息**：' + item.extra : '';
  return '### ' + item.title + '
