';
}

const errSec = data.errors && data.errors.length ? '
---

> ⚠️ **抓取警告**（' + data.errors.length + ' 个源异常）
' + data.errors.map(function(e){ return '> - ' + e; }).join('
') + '
' : '';

const report = '# BriefFeed 情报简报 — ' + dateStr + ' ' + timeStr + '

> 生成时间：' + data.fetchedAt + ' | 通过筛选：' + items.length + ' 条（论文 ' + papers.length + '、博客 ' + blogs.length + '、GitHub ' + githubs.length + '）

---

## 一、今日重点论文

' + (papers.length ? papers.map(fmt).join('') : '_今日暂无高相关度论文。_
